 /// Get disk usage for a path (like df)
+/// Uses statvfs on POSIX systems
 pub fn disk_usage(path: []const u8) !DiskUsage {
-    _ = path;
-    // This requires platform-specific syscalls
-    // For now, return a stub
-    return .{
-        .total = 0,
-        .used = 0,
-        .free = 0,
